+        assert!(visible[1].thread_id.is_none()); // thread_id redacted
+        assert!(visible[1].from_agent.is_some()); // agent name NOT redacted in contact_blocked
+        // Audit
+        assert_eq!(audit.len(), 1);
+        assert_eq!(audit[0].action, AuditAction::Redacted);
